mapper.update:
create table if not exists zephyr_conversations (
  id varchar(64) primary key,
  user_name varchar(64) not null,
  title varchar(256) not null,
  created_at bigint,
  workspace_id varchar(64),
  updated_at bigint
);
create index if not exists idx_zephyr_conv_user on zephyr_conversations(user_name);
create index if not exists idx_zephyr_conv_updated on zephyr_conversations(updated_at desc);

create table if not exists zephyr_messages (
  id varchar(64) primary key,
  conversation_id varchar(64) not null,
  role varchar(16) not null,
  content text,
  thinking text,
  tool_calls_json text,
  tool_call_id varchar(128),
  created_at bigint
);
create index if not exists idx_zephyr_msg_conv on zephyr_messages(conversation_id);
create index if not exists idx_zephyr_msg_created on zephyr_messages(created_at);
